    private List<String> extractArticleLinksJsoup(PortalConfig portal) {
        try {
            log.info("[SCRAPER] Jsoup home: " + portal.homeUrl());

            Connection.Response res = Jsoup.connect(portal.homeUrl())
                    .userAgent(ua())
                    .header("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
                    .header("Accept-Language", "pt-BR,pt;q=0.9,en;q=0.8")
                    .header("Referer", portal.homeUrl()) // referrer = prÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³pria home (como POC)
                    .timeout(FETCH_TIMEOUT)
                    .followRedirects(true)
                    .execute();

            int status = res.statusCode();
            log.info("[SCRAPER] " + portal.name() + " home HTTP " + status);
            if (status == 403 || status == 429) {
                log.warning("[SCRAPER] BLOQUEADO " + status + ": " + portal.homeUrl());
                return Collections.emptyList();
            }

            Document doc = res.parse();
            if (doc == null) return null;
            Elements allAs = doc.select("a[href]");
            log.info("[SCRAPER] " + portal.name() + ": " + allAs.size() + " links totais na home");

            LinkedHashMap<String, String> unique = new LinkedHashMap<>();
            int blocked = 0;

            for (Element a : allAs) {
                String url   = a.absUrl("href");
                String title = a.text() == null ? "" : a.text().trim();

                if (url.isEmpty() || title.isEmpty()) continue;
                if (url.contains("#")) continue;

                String clean = url.split("\\?")[0];

                // Checa blocked paths
                boolean isBlocked = false;
                for (String b : portal.blockedPaths()) {
                    if (clean.contains(b)) { isBlocked = true; break; }
                }
                if (isBlocked) { blocked++; continue; }

                // Valida estrutura da URL (tÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©cnica do POC)
                if (!isValidArticleUrl(clean, portal)) continue;

                unique.putIfAbsent(clean, title);
                if (unique.size() >= MAX_PER_PORTAL) break;
            }

            log.info("[SCRAPER] " + portal.name() + ": " + unique.size() + " artigos vÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡lidos | " + blocked + " bloqueados por path");
            return new ArrayList<>(unique.keySet());

        } catch (Exception e) {
            log.warning("[SCRAPER] Jsoup home falhou " + portal.name() + ": " + e.getClass().getSimpleName() + " - " + e.getMessage());
            return Collections.emptyList();
        }
    }

