    private static String cleanTitle(String title, String portalName) {
        if (title == null) return "";
        return title.replaceAll("\\s*[|\\-ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¦ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã¢â‚¬Å“ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â]\\s*" + java.util.regex.Pattern.quote(portalName) + ".*$", "").trim();
    }

    private static Instant parseDate(String... candidates) {
        for (String s : candidates) {
            if (s == null || s.isBlank()) continue;
            try { return Instant.parse(s); } catch (Exception ignored) {}
            try { return java.time.OffsetDateTime.parse(s).toInstant(); } catch (Exception ignored) {}
        }
        return null;
    }

    private static String firstNonBlank(String... candidates) {
        for (String s : candidates) if (s != null && !s.isBlank()) return s;
        return null;
    }

    private static String normalizeArticleUrl(String candidate, String fallback) {
        String value = firstNonBlank(candidate, fallback);
        if (value == null) return null;
        String normalized = value.trim();
        int hashIdx = normalized.indexOf('#');
        if (hashIdx >= 0) normalized = normalized.substring(0, hashIdx);
        return normalized;
    }

    private static String safe(String s) { return s == null ? "" : s; }

    private static List<NewsItem> dedup(List<NewsItem> items) {
        Map<String, NewsItem> map = new LinkedHashMap<>();
        for (NewsItem item : items) {
            if (!map.containsKey(item.slug())) {
                map.put(item.slug(), item);
            } else {
                NewsItem ex = map.get(item.slug());
                if (!item.image().startsWith("/") && ex.image().startsWith("/"))
                    map.put(item.slug(), item);
            }
        }
        return new ArrayList<>(map.values());
    }

    private static String generateSlug(String title, String url) {
        if (title == null || title.isBlank()) return shortHash(url);
        String t = java.text.Normalizer.normalize(title, java.text.Normalizer.Form.NFD)
                .replaceAll("\\p{InCombiningDiacriticalMarks}+", "")
                .toLowerCase(Locale.ROOT)
                .replaceAll("[^a-z0-9\\s]", " ")
                .replaceAll("\\s+", "-")
                .replaceAll("(^-+|-+$)", "");
        String suffix = shortHash(url == null ? title : url);
        String slug = t.isBlank() ? suffix : (t + "-" + suffix);
        if (slug.length() > 90) slug = slug.substring(0, 90).replaceAll("-+$", "") + "-" + suffix;
        return slug;
    }

    private static String shortHash(String s) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] h = md.digest((s == null ? "" : s).getBytes(StandardCharsets.UTF_8));
            StringBuilder hex = new StringBuilder();
            for (int i = 0; i < 4; i++) hex.append(String.format("%02x", h[i]));
            return hex.toString();
        } catch (Exception e) { return Integer.toHexString(Objects.hashCode(s)); }
    }

    private PortalConfig findPortal(String name) {
        return PORTALS.stream().filter(p -> p.name().equalsIgnoreCase(name)).findFirst().orElse(null);
    }
